function safeStringify(value: any, indent = 2) {
  const cache = new Set<any>()

  return JSON.stringify(
    value,
    (key, value) => {
      if (typeof value === 'object' && value !== null) {
        if (cache.has(value)) {
          return `[Circular *]`
        }

        cache.add(value)
      } else if (typeof value === 'bigint') {
        return value.toString()
      }

      return value
    },
    indent,
  )
}

