    const { colors } = writer.context

    writer
      .writeLine('[')
      .withIndent(() => writer.writeJoined(fieldsSeparator, this.items).newLine())
      .write(']')

    if (this.hasError) {
      writer.afterNextNewline(() => {
        writer.writeLine(colors.red('~'.repeat(this.getPrintWidth())))
      })
    }
  }

  override asObject(): undefined {
    return undefined
  }
}
